 /**
 * Generates Unique username in specific format. Firstname 1st letter, middle initial and complete lastname.
 * The username will be truncated if the name exceeds 20 characters.
 *
 * @param firstName the first name of identity
 * @param lastName the last name of identity
 * @return the username
 */
   public String generateUserName(String firstName, String lastName){
    String methodName = "generateUserName";
    logger.debug("Entering"+methodName);
    String userName = null;
    Boolean duplicate=false;
    Boolean duplicateIIQ=false;
    String filteredFname = filterSpecialCharacter(firstName);
    String filteredLname = filterSpecialCharacter(lastName);  
    if(Util.isNullOrEmpty(filteredLname)){
      filteredLname = "";
    }
    if(Util.isNotNullOrEmpty(filteredFname) && Util.isNotNullOrEmpty(filteredLname) && (filteredLname.length() >= 7))
    {
      userName = filteredFname.substring(0,1)+filteredLname.substring(0,7);      
      duplicateIIQ = checkDuplicateUserName(userName); // Create logic to check username in IIQ
      if(!duplicateIIQ)
      {
        duplicate = checkDuplicatesAMAccountName(userName);
      }
    }
    if (Util.isNotNullOrEmpty(filteredFname) && Util.isNotNullOrEmpty(filteredLname) && ((filteredLname.length() < 7) || duplicate || duplicateIIQ))
    {
      for(int i = 1; i < 10000 ; i++)
      {           
        if (filteredLname.length() >= 3)
        {
          userName = filteredFname.substring(0,1) + filteredLname.substring(0,3) + String.format("%04d", i);  
        }
        else
        {
          userName = filteredFname.substring(0,1) + filteredLname + String.format("%04d", i);
        }  
       
        duplicateIIQ = checkDuplicateUserName(userName);
        
        if(!duplicateIIQ)
        {
          duplicate = checkDuplicatesAMAccountName(userName);
        }
        if(duplicate || duplicateIIQ)
        {
		  if(i>=9999) {
		    throw new Exception("generateUserName duplicate check exceeded more than 9999 ");
		  }
          continue;		  
        }
        else
        {
          break;
        }      
      }
    }	
    logger.debug("Exiting"+methodName);
    return userName;
  }
  /**
 * Generates Unique username in specific format. 
 *
 * @return the username
 */
  public String initialUserName(){
    String methodName = "initialUserName";
    logger.debug("Entering"+methodName);
    Boolean duplicateIIQ = false;
    String result = "";  
    String userName = "";
    int count = 0;
    
    do {
      userName = generateNextInitialName();
      duplicateIIQ = checkDuplicateUserName(userName); // Create logic to check username in IIQ
      count++;
    }while(duplicateIIQ && count <=2000);
    if(!duplicateIIQ){
      result = userName;
    }
    logger.debug("Exiting"+methodName);
    return result ;
  }
  
  /**
	 * Filter special character from the Firstname, Lastname 
	 * @param attrValue Firstname/Lastname
	 * @return Filtered String
	 */
  public String filterSpecialCharacter(String attrValue) {
    logger.debug("Entering filterSpecialCharacter method");
    String filterString = null;
    if (Util.isNotNullOrEmpty(attrValue)) {
      Pattern pattern = Pattern.compile("[a-zA-Z0-9]*");
      Matcher matcher = pattern.matcher(attrValue);
      if (matcher.find()) {
        filterString = attrValue.replaceAll("[^a-zA-Z0-9]", "");
      } else {
        filterString = attrValue;
      }
    }
    logger.debug("Exiting filterSpecialCharacter method");
    return filterString;
  }
  /**
	 * Check uniqueness of the username
	 * @param username the username
	 * @return The count of existing users, where their username starts with similar name
	 */
  public boolean checkDuplicateUserName(String username) {
    String methodName = "checkDuplicateUserName";
    logger.debug("Entering"+methodName);
    boolean existsIIQ = false;
    Filter filter1 = Filter.ignoreCase(Filter.eq("samAccountName", username));
    Filter filter2 = Filter.ignoreCase(Filter.eq("name", username));
    Filter filter = Filter.or(filter1,filter2);
    QueryOptions qo = new QueryOptions();
    qo.add(filter);
    Integer count = context.countObjects(Identity.class,qo);

    if(count > 0 )
    {
      existsIIQ=true;
    }
    logger.debug("Exiting"+methodName);
    return existsIIQ;
  }
  /**
	 *  Gets the LDAP connection context object to use to establish the LDAP connection
	 *  @param host 
	 *  @param user 
	 *  @param password 
	 *  @param isSSL 
	 *  @return 
	 */
	private DirContext getLDAPContext(String host, String user, String password, boolean isSSL) throws Exception {
		Hashtable env = new Hashtable();
		env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
		env.put(Context.PROVIDER_URL, "ldap://" + host);
		env.put(Context.SECURITY_PRINCIPAL, user);
		env.put(Context.SECURITY_AUTHENTICATION, "simple");
		env.put(Context.SECURITY_CREDENTIALS, password);
		env.put("com.sun.jndi.ldap.connect.timeout", "10000");
		if (isSSL) {
			env.put("java.naming.security.protocol", "ssl");
		}
		DirContext dirContext = new InitialLdapContext(env, null);
		return dirContext;
	}
	/**
	 *  Returns a Map containing the domainSettings of the specified AD application.
	 *  if there are multiple domains configured in the AD application, this will only return the first one found
	 *  @param adAppName 
	 *  @return 
	 */
	public Map getADDomainSettings(Application app){
		log.trace("Entering getADDomainSettings::" + adAppName);
		Map domainSettings = null;
		List domainSettingsList = app.getAttributeValue("domainSettings");
		if(domainSettingsList != null &amp;&amp; !domainSettingsList.isEmpty()){
			domainSettings = domainSettingsList.get(0);
		}
		log.trace("Exiting getADDomainSettings::" + domainSettings);
		return domainSettings;
	}
  /**
	 *  Checks if any objects matching the specified search filter exist in AD
	 *  @param adAppName name of AD application to look up connection details to
	 *  @param searchFilter LDAP filter string
	 *  @return true if exists, false if not
	 */
	public boolean isExistsInAD(Application app, String searchFilter, String searchDN){
		log.trace("Entering isExistsInAD::" + app);
		Map domainSettings = getADDomainSettings(app);
		boolean retValue = false;
		if(domainSettings != null){
			List domainControllers = domainSettings.get("servers");
			String username = domainSettings.get("user");
			String password = context.decrypt(domainSettings.get("password"));
			//String searchDN = domainSettings.get("domainDN");
			Boolean isSSL = (Boolean) domainSettings.get("useSSL");
			if(domainControllers != null){
				for(String server : domainControllers){
					log.debug("Attempting to query AD server: " + server);
					try {
						DirContext ctx = getLDAPContext(server, username, password, isSSL);
						SearchControls searchCtls = new SearchControls();
						String[] returnedAtts = { "sAMAccountName" };
						searchCtls.setReturningAttributes(returnedAtts);
						searchCtls.setSearchScope(SearchControls.SUBTREE_SCOPE);
						NamingEnumeration results = ctx.search(searchDN, searchFilter, searchCtls);
						if (results.hasMoreElements()) {
							retValue = true;
						}
						break;
					} catch (Exception ex){
						log.debug("Failed to query LDAP server: " + server, ex);
					}
				}
			}
		}
		log.trace("Exiting isExistsInAD::" + retValue);
		return retValue;
	}
  /**
		 * tell if generate username already exists or not in all exists AD Forests
		 * @param sAMAccountName
		 * @return if generate username exists or not in all AD forest
		 */
   public boolean checkDuplicatesAMAccountName(String sAMAccountName){
    String methodName = "checkDuplicatesAMAccountName";
    logger.debug("Entering "+methodName);
    Boolean exists=false;
    Custom domainsCust = context.getObjectByName(Custom.class, "Ascension-Custom-AD-DomainMapping");
		String searchFilter = "(&(objectClass=person)(ObjectClass=user)(sAMAccountName=" + sAMAccountName + "))";
    if(null != domainsCust){
      List appList = domainsCust.get("Applications");
      Map dnMappings = domainsCust.get("DNMapping");
      if (appList != null && dnMappings != null) {
        for (String appName : appList){
		if(dnMappings.containsKey(appName)){
          Application app = context.getObjectByName(Application.class, appName);
          if(app == null)
            continue;
          List searchDNs = new ArrayList(dnMappings.get(appName));
		  if(searchDNs!=null && !searchDNs.isEmpty()){
          List existingSearchDNs = (List) app.getAttributeValue("searchDNs");
          if(existingSearchDNs != null && !existingSearchDNs.isEmpty()){
            for(Map searchDNConf : existingSearchDNs){
              String searchDN = searchDNConf.get("searchDN");
              if(searchDN != null)
                searchDNs.add(searchDN);
            }
          }
          for(String searchDN : searchDNs){
            if(isExistsInAD(app, searchFilter, searchDN)){
              exists = true;
              break;
            }
          }
          if(exists)
            break;
        }
		}
		}
      }
    }
    logger.debug("Exiting " + methodName + " - " + exists);
    return exists;
  }
  /**
	 * Audit log for executed pland
	 * @param accReq
   * @param flow
   * @param action
   * @param userName
   * @param list
   * @param dataMap
   *@param identityRequestId request id 
	 */
  public void logAudit(AccountRequest accReq, String flow ,String action, String userName, ArrayList list, HashMap dataMap , String identityRequestId){
    logger.debug("Entering audit event");
    if(Auditor.isEnabled(action)){
      AuditEvent event = new AuditEvent();

      event.setTarget(userName);     
      event.setAction(action);     
      event.setString1(flow);
      event.setString2("Access Request ID : "+identityRequestId);

      Attributes attributes = new Attributes(); 
      if(!Util.isEmpty(dataMap)){
        for (Map.Entry mapElement : dataMap.entrySet()) {
          attributes.put(mapElement.getKey(),mapElement.getValue());
        }
        event.setAttributes(attributes);
      }
      
      if(Util.nullSafeCaseInsensitiveEq(flow,"ImmediateTermination")){        
        event.setString4("User "+userName+" is terminated by "+dataMap.get("launcher")+" using 'Immediate Disablement' Quicklink");
        event.setString3("Launched workflow Ascension-Workflow-Immediate-Termination: "+userName);
        event.setSource(dataMap.get("launcher"));
      }

        if(null != accReq){
          event.setApplication(accReq.getApplication());
          event.setAccountName(accReq.getNativeIdentity());
        }
      else{
          event.setAccountName(userName);
      }
        Auditor.log(event);
        context.commitTransaction();
      }
    logger.debug("Exiting Audit event");   
  }
  /**
	 * Convert given date format to String
	 * @param date
	 * @return String format of date
	 */
  public String convertDateToString(Date date){
    logger.debug("Entering Method for Converting Date to String");
    String dateString = null;
    String format = "yyyy-MM-dd";
    Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
    try{
      if(custom!=null && Util.isNotNullOrEmpty(custom.get("DateFormat"))){
        format = custom.get("DateFormat");
      }
      SimpleDateFormat dateFormatIIQ = new SimpleDateFormat(format);
      if(null != date){
        dateString = dateFormatIIQ.format(date);
      }  
    }catch(Exception ex){
      logger.error("Exception in Converting Date to String"+ex);
    }
    if(null != custom){
      //comment decache //context.decache(custom);
    }
    logger.debug("Exit Method for Converting Date to String"); 
    return dateString;
  }
