  /**
	 * Convert given date string  format to AD date format date String
	 * @param date in string
	 * @return String AD format of date
	 */
  public String getADFormatedDateString(String inputDateString) throws Exception {
    logger.debug("Entering ::getADFormatedDateString  inputDateString "+inputDateString );
    String adFormatedDate = "";
    String format = "yyyy-MM-dd";
    SimpleDateFormat displayFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss Z", Locale.getDefault());
    SimpleDateFormat adSDF = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss a z");
    Date parseDate = null;
    Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
    if(custom!=null && Util.isNotNullOrEmpty(custom.get("DateFormat"))){
      format = custom.get("DateFormat");
    }
    try {
      parseDate = displayFormat.parse(inputDateString);
    } catch (ParseException e) {
      try {
        SimpleDateFormat fgSDF = new SimpleDateFormat(format, Locale.getDefault());
        parseDate = fgSDF.parse(inputDateString);
      } catch (ParseException e1) {
        logger.error("::getADFormatedDateString :: Invalid input date format " + e1);
      }
    }
    if (parseDate != null) {
      adFormatedDate = adSDF.format(parseDate);
    }
    if(null != custom){
      //comment decache //context.decache(custom);
    }
    logger.debug("Exiting ::getADFormatedDateString :: AD date =" + adFormatedDate);
    return adFormatedDate;
  }
  /**
	 * Check uniqueness of the RACf TPXID
	 * @param TPXID
	 * @return if generated TPXID already exists or not
	 */
  public boolean checkDuplicateTPXID(String tpxId) {
    String methodName = "checkDuplicateTPXID";
    logger.debug("Entering"+methodName);
    boolean exists = false;
    String attributeVal = null;
    
    QueryOptions queryOptions = new QueryOptions();
    queryOptions.addFilter(Filter.eq("application.name", "Invision"));
    Iterator objectList = context.search(Link.class, queryOptions);
    
    if (objectList != null) {
      while (objectList.hasNext()) {
        Link linkObj = objectList.next();
        if(linkObj != null && linkObj.getAttribute("GenTPXID") != null){
          attributeVal= linkObj.getAttribute("GenTPXID");
          if(attributeVal.equalsIgnoreCase(tpxId)){
            exists = true;
          }
        }
      }
    }
    Util.flushIterator(objectList);
    logger.debug("Exiting"+methodName);
    return exists;
  }
  
