  /**
	 * @Get deleted AD account sAMAccountName
	 * @param Identity
	 * @return deleted account samaccountname
	 */
  public String checkExistingSamAccName(Identity identity)
  {
    logger.debug("Entering method checkExistingSamAccName");
    String firstName = "";
    String lastName = "";
    String ssnVal = "";
    String dobVal = "";
    String samName = "";
    Map result = new HashMap();
    Statement stmt = null;
    ResultSet rs = null;
    Connection conn = null;
    if(null != identity){
      firstName = identity.getFirstname();
      lastName = identity.getLastname();
      ssnVal = encryptAES(identity.getAttribute("ssn")); 
      dobVal = encryptAES(identity.getAttribute("dob"));
    }
    String query = "SELECT SAM_NAME FROM DELETEDADACCOUNT WHERE FIRST_NAME = '"+firstName+"' and LAST_NAME = '"+lastName+"' and SSN = '"+ssnVal+"' and DOB = '"+dobVal+"'";
    try {
      conn = context.getJdbcConnection();
      if(conn!=null){
        stmt = conn.createStatement();
        rs = stmt.executeQuery(query);
        while (rs!=null && rs.next()) {
          if(null!=rs.getString("Sam_Name")){
            StringTokenizer stringTokenizer = new StringTokenizer(rs.getString("Sam_Name"), "\\"); 
            while(stringTokenizer.hasMoreTokens()) {
              samName = stringTokenizer.nextToken(); 
            } 
          }
        }
        stmt.close();
        rs.close();
        conn.close();
      }
    } catch (SQLException se) {
      logger.error("Exception in checkExistingSamAccName from database: " + se.getMessage());
    } catch (Exception e) {
      logger.error("Exception in checkExistingSamAccName from database: " + e.getMessage());
    } finally {
      try {
        if (stmt != null){	stmt.close();	}
        if (rs != null){	rs.close();	}
        if (conn != null){	conn.close();	}
      } catch (SQLException se) {
        logger.error("Exception in database Operation : " + se.getMessage());
      }
    }
    logger.debug("Exiting method checkExistingSamAccName");  
    return samName;
  }
  
  /**
	 * Get advance time  
	 * @param number in Minutes 
	 * @return advanceddate
	 */
  public advanceTimeByMinutes(String timeToAdvance)
  {
    logger.debug("Entering advanceTimeByMinutes");  

    logger.debug("Perform Sending Service now Notification after 10 min :: Entering");
	int number;
    try{
       number = Integer.parseInt(timeToAdvance);
    }
    catch (NumberFormatException ex){
      logger.error("Exception in Converting String to int"+ex);
    }
    GregorianCalendar currCal = (GregorianCalendar) GregorianCalendar.getInstance();        
    currCal.add(Calendar.MINUTE, number);

    logger.debug("Perform Sending Service now Notification after 10 min  :: Exiting :: scheduleDate = "+currCal.getTime());   
    logger.debug("Existing advanceTimeByMinutes");  
    return currCal.getTime();

  }
  
