  /**
	 *get Primary Identity name By input identity name. 
   * If the input identity is persona type child then the method will return the parent persona name.
   * if the input identity is not persona type child then the method will return same input value.
	 * @param identityName
	 * @return String format of date
	 */
  public String getPrimaryIdentityNameByName(String correlatedIdentityName){
   logger.debug("getPrimaryIdentityNameByName Entering");
   Identity idn = context.getObjectByName(Identity.class, correlatedIdentityName);
    if(idn != null){
      String personaType = idn.getStringAttribute("personaType");
      if(Util.nullSafeCaseInsensitiveEq(personaType,"Child")){
        if(Util.isNotNullOrEmpty(idn.getStringAttribute("parentPersonaName"))){
          QueryOptions qo = new QueryOptions();
          qo.add(Filter.ignoreCase(Filter.eq("name", idn.getStringAttribute("parentPersonaName"))));
          int count = context.countObjects(Identity.class, qo);
          if(count >0){
            correlatedIdentityName = idn.getStringAttribute("parentPersonaName");
          }
        }
      }
      //comment decache //context.decache(idn);
    }
     logger.debug("getPrimaryIdentityNameByName Exiting");
   
    return correlatedIdentityName;
  }

  /**
	 * get IdentityName By Identity Property and value
	 * @param propertyName , value
	 * @return String name
	 */
  public String getIdentityNameByProperty(String propertyName , String value){
    logger.debug("getIdentityNameByProperty Entering");
    String identityName = "";
    try{
      QueryOptions qoEmp = new QueryOptions();
      qoEmp.add(Filter.ignoreCase(Filter.eq(propertyName, value)));
      Iterator itr = context.search(Identity.class, qoEmp, "name");
      if(!Util.isEmpty(itr) && itr.hasNext()){
        Object []eachObject = (Object[]) itr.next();
        identityName = (String) eachObject[0];
      }
      if(itr!=null){
        Util.flushIterator(itr);
      }
    }catch(GeneralException ge){
      logger.error("Exception in get Identity Name by Property "+ge.getMessage());
    }
     logger.debug("getIdentityNameByProperty Exiting");
   
    return identityName;
   }
                  
  /**
	 * get samaccountname from principalname value
	 * @param value
	 * @return String samaccountname
	 */
  public String getSamAccountNameFromPrincipalName(String value){
    if(Util.isNotNullOrEmpty(value) && value.contains("\\")){
      StringTokenizer stringTokenizer = new StringTokenizer(value, "\\"); 
      while(stringTokenizer.hasMoreTokens() ){
        value = stringTokenizer.nextToken();
      }
    }

    return value;
  }
  
  /**
	 * Refresh the identity
	 * @param sourceIdentity is an identity name 
   * @param attributesMap - attributes/Options of refresh identity cube Task
	 */
  public void refreshIdentityCube(String sourceIdentity, Map attributesMap){

    Attributes attr = new Attributes();  
    String nameFilter = "name=="+"\""+sourceIdentity+"\""; 
    attr.put("filter",nameFilter);

    if(!Util.isEmpty(attributesMap)){
      for (Map.Entry entry : attributesMap.entrySet()){
        if(null !=entry){
          attr.put(entry.getKey(),entry.getValue());
        }
      }
    }
    try {
      TaskManager tm = new TaskManager(context);
      tm.run ("Identity Refresh", attr);
    } catch (Exception e) {
      logger.error("Exception processing request for Identity Refresh run from rule");
    }
  }
  
  
   public String getOUInformation(String identityName){

    String createDN ="";
    HashMap domainMap = new HashMap();
    HashMap activeOUMap = new HashMap();
    String createDN = null;
    String locationID = null;
    String domain = null;

    if(Util.isNotNullOrEmpty(identityName) ){
      Identity identity = context.getObjectByName(Identity.class,identityName);
      if(null != identity){

        domain = identity.getAttribute("domain");
        locationID = identity.getAttribute("buildingId");

        Custom custDN = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");

        if(custDN != null && null != custDN.get("DomainOUMapping")){
          domainMap = custDN.get("DomainOUMapping");
          if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get(domain)){  
            activeOUMap = domainMap.get(domain).get("activeOU");
            if(null != activeOUMap && !activeOUMap.isEmpty() && Util.isNotNullOrEmpty(locationID) && Util.isNotNullOrEmpty(activeOUMap.get(locationID))){
              createDN = activeOUMap.get(locationID);
            }
            else{
              createDN = activeOUMap.get("DEFAULT");
            }
          }
          //comment decache //context.decache(custDN);
        }
        //comment decache //context.decache(identity);
      }
    }

    return createDN;

  }
  
  /**
	 * Get AD domain value in from Identity attribute domain for which AD domain and identity domain is different
	 * @param Identity Attribute Domain
	 * @return domain for the respective account
	 */
  public String domainConversion(String domain)
  {
    logger.debug("Entering method domainConversion");
    String domainValue = domain;
    Map domainOUMap = new HashMap();
    
    Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
    if(null != custom){
      domainOUMap = custom.get("OUDomainMapping");  
      //comment decache //context.decache(custom);
    }
    if(!Util.isEmpty(domainOUMap) && !Util.isEmpty(domainOUMap.keySet()) && domainOUMap.keySet().contains(domainValue)){     
      domainValue = domainOUMap.get(domainValue);
    }    

    logger.debug("Exiting method domainConversion");

    return domainValue;
  }
